window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["c7-low-voltage"] = window.COURSE_LANG["c7-low-voltage"] || {};
window.COURSE_LANG["c7-low-voltage"]["es"] = [
  {"id":1,"q":"La ley de Ohm establece que:","opts":["El voltaje es igual a la corriente por la resistencia (V = I × R)","La potencia siempre es igual al voltaje","La resistencia es igual al voltaje por la corriente","La corriente es independiente del voltaje"],"re":"La ley de Ohm, V = I × R, relaciona voltaje, corriente y resistencia y es la base del trabajo en circuitos."},
  {"id":2,"q":"Un circuito de 24 voltios alimenta un dispositivo con 600 ohmios de resistencia. El consumo de corriente es:","opts":["14,400 A","0.04 A","2.4 A","25 A"],"re":"Por la ley de Ohm, I = V/R = 24 / 600 = 0.04 A (40 mA), una corriente típica de señalización de bajo voltaje."},
  {"id":3,"q":"La potencia eléctrica en vatios se calcula como:","opts":["Voltaje dividido por la corriente","Corriente dividida por la resistencia","Voltaje por corriente (P = V × I)","Resistencia por voltaje"],"re":"La potencia es igual al voltaje por la corriente (P = V × I); también se obtiene como I²R o V²/R."},
  {"id":4,"q":"La diferencia principal entre un circuito de señal y uno de potencia es que el de señal:","opts":["Siempre usa mayor voltaje","Lleva grandes cantidades de energía para hacer trabajo","No puede usar conductores de cobre","Lleva información a baja energía en lugar de entregar potencia de trabajo"],"re":"Los circuitos de señal transmiten información (datos, audio, video, control) a baja energía; los de potencia entregan energía para alimentar cargas."},
  {"id":5,"q":"La clasificación CSLB C-7 de Sistemas de Bajo Voltaje cubre, en general, sistemas de comunicación y bajo voltaje que no exceden:","opts":["91 voltios","240 voltios","480 voltios","600 voltios"],"re":"El alcance del C-7 cubre sistemas de comunicación y bajo voltaje de energía limitada que no exceden 91 voltios a tierra."},
  {"id":6,"q":"La corriente continua (CC) se diferencia de la alterna (CA) en que la CC:","opts":["Invierte su dirección 60 veces por segundo","Fluye en una sola dirección constante","No puede alimentar dispositivos electrónicos","Solo existe en la fibra óptica"],"re":"La CC fluye de forma constante en una dirección; la CA invierte su dirección periódicamente (60 Hz en Norteamérica). La mayoría de los dispositivos de bajo voltaje usan CC."},
  {"id":7,"q":"En un circuito en serie, la corriente es:","opts":["La misma a través de cada componente","Diferente en cada componente","Siempre cero","Igual al voltaje total"],"re":"Un circuito en serie tiene un solo camino, así que la misma corriente pasa por cada componente; el voltaje se reparte entre ellos."},
  {"id":8,"q":"Un multímetro ajustado para medir voltaje se conecta al circuito:","opts":["En paralelo, entre los dos puntos","En serie, interrumpiendo el circuito","Solo con la corriente apagada","A través de la varilla de tierra"],"re":"El voltaje se mide en paralelo (entre) dos puntos; la corriente se mide en serie, insertando el medidor en el camino."},
  {"id":9,"q":"La caída de voltaje en un tendido largo de bajo voltaje es un problema porque:","opts":["Aumenta el voltaje de alimentación","No afecta a los dispositivos","Reduce el voltaje que llega al dispositivo, que puede fallar","Solo importa en circuitos de potencia de CA"],"re":"La resistencia de los conductores largos baja el voltaje, así que el dispositivo lejano puede recibir muy poco para operar bien; un cable más grueso reduce la caída."},
  {"id":10,"q":"Los pares del cable de par trenzado se trenzan principalmente para:","opts":["Facilitar el enrollado del cable","Aumentar la clasificación de voltaje","Reducir la diafonía y la interferencia electromagnética","Añadir peso para dar resistencia"],"re":"El trenzado cancela gran parte del ruido y la diafonía que se captan entre pares, mejorando la calidad de la señal."},
  {"id":11,"q":"Para el cableado estructurado Categoría 5e/6, el tendido permanente (horizontal) máximo recomendado es de unos:","opts":["90 metros (295 ft)","30 metros (100 ft)","300 metros (985 ft)","500 metros (1,640 ft)"],"re":"El tendido horizontal se limita a unos 90 m, dejando espacio para los cables de parcheo, de modo que el canal completo se mantenga dentro de 100 m (328 ft)."},
  {"id":12,"q":"Un canal de par trenzado balanceado (Cat 5e/6) no debe exceder una longitud total de:","opts":["100 metros (328 ft)","100 pies","1,000 pies","Una milla"],"re":"El canal total, incluidos los cables de parcheo, se limita a 100 m (328 ft); más allá la señal se degrada."},
  {"id":13,"q":"En comparación con la configuración T568A, la T568B:","opts":["Usa cables completamente diferentes","Intercambia los pares naranja y verde","Solo funciona con fibra","Tiene seis conductores en lugar de ocho"],"re":"T568A y T568B usan los mismos ocho conductores; solo intercambian las posiciones de los pares naranja y verde."},
  {"id":14,"q":"En el sistema American Wire Gauge (AWG), un número de calibre menor significa:","opts":["Un cable más delgado con más resistencia","Ningún cambio en el tamaño del cable","Un cable de mayor diámetro con menos resistencia","Un cable que no puede conducir corriente"],"re":"El AWG es inverso: un número menor es un conductor más grueso con menor resistencia y mayor capacidad de corriente (el 18 AWG es más grande que el 22 AWG)."},
  {"id":15,"q":"La fibra óptica monomodo, en comparación con la multimodo, se usa en general para:","opts":["Solo cables de parcheo cortos","Conducir potencia eléctrica","Solo telefonía analógica","Distancias mucho más largas con menor atenuación"],"re":"La fibra monomodo (1310/1550 nm) tiene baja atenuación y poca dispersión, así que lleva señales a distancias mucho mayores que la multimodo."},
  {"id":16,"q":"La fibra multimodo se opera típicamente a una longitud de onda de:","opts":["850 nm","1,550 nm","91 voltios","48 kHz"],"re":"La fibra multimodo suele operar a 850 nm (y 1300 nm) para enlaces cortos económicos; la monomodo usa 1310/1550 nm."},
  {"id":17,"q":"El conector modular de 8 posiciones usado en el cable de red de par trenzado se llama comúnmente:","opts":["Conector RJ45 (8P8C)","Conector BNC","Conector ST","Conector tipo F"],"re":"El par trenzado de red termina en un conector modular de 8 posiciones y 8 contactos llamado RJ45; BNC, ST y tipo F son conectores de coaxial o fibra."},
  {"id":18,"q":"Para terminar el par trenzado en un jack o panel de parcheo, debes:","opts":["Destrenzar los pares lo más atrás posible","Soldar cada conductor","Mantener el trenzado del par lo más cerca posible de la terminación","Quitar todo el aislamiento de color"],"re":"Mantener el trenzado hasta el punto de ponchado conserva el rendimiento; destrenzar de más aumenta la diafonía."},
  {"id":19,"q":"En un sistema de alarma contra incendios, un detector de humo o una estación manual se clasifica como:","opts":["Dispositivo de notificación","Dispositivo iniciador","Fuente de alimentación","Relé de control"],"re":"Los dispositivos que detectan un incendio o se activan manualmente (detectores de humo/calor, estaciones manuales, interruptores de flujo) son dispositivos iniciadores."},
  {"id":20,"q":"Las bocinas y luces estroboscópicas que alertan a los ocupantes del edificio se llaman:","opts":["Dispositivos iniciadores","Protectores primarios","Dispositivos de notificación","Repetidores"],"re":"Los dispositivos de notificación (bocinas/altavoces audibles y luces estroboscópicas visibles) alertan a los ocupantes cuando existe una alarma."},
  {"id":21,"q":"Un detector de calor de temperatura fija común se ajusta para alarmar a aproximadamente:","opts":["75°F","350°F","600°F","135°F"],"re":"Un detector de calor de temperatura fija muy usado se activa cerca de los 135°F; los de tasa de aumento responden a una subida rápida de temperatura."},
  {"id":22,"q":"Un detector de humo fotoeléctrico detecta el humo mediante:","opts":["La medición de la temperatura del aire","El conteo de personas en la sala","La medición de la humedad","La detección de luz dispersada por las partículas de humo"],"re":"Los detectores fotoeléctricos detectan la luz dispersada por el humo y responden bien a fuegos lentos y latentes; los de ionización reaccionan más rápido a fuegos con llama."},
  {"id":23,"q":"En un circuito de dispositivos iniciadores Clase B, un solo cable abierto (roto):","opts":["Deshabilita los dispositivos ubicados después de la ruptura","No tiene ningún efecto","Aumenta el voltaje de alimentación","Activa una alarma general automáticamente"],"re":"Un circuito Clase B es una sola trayectoria radial con un dispositivo de fin de línea; una apertura deshabilita todo lo que está después de la ruptura, por eso reporta una falla."},
  {"id":24,"q":"Un circuito de alarma Clase A mejora la confiabilidad porque:","opts":["No usa cableado","Funciona a 120 voltios","Se alimenta por ambos extremos, así una sola ruptura deja los dispositivos funcionando","No necesita señal de falla"],"re":"Una trayectoria Clase A regresa al panel y se alimenta por ambos extremos, así que una sola apertura mantiene todos los dispositivos operando mientras señala una falla."},
  {"id":25,"q":"Una resistencia de fin de línea en un circuito iniciador convencional sirve para:","opts":["Aumentar el volumen de la alarma","Supervisar el cableado por aperturas","Convertir CA en CC","Alimentar las luces estroboscópicas"],"re":"La resistencia de fin de línea permite al panel vigilar la continuidad del circuito; la pérdida de esa corriente de supervisión indica una apertura (falla)."},
  {"id":26,"q":"Por accesibilidad, la palanca operable de una estación manual de alarma se monta en general a no más de:","opts":["24 pulgadas sobre el piso","6 pies sobre el piso","8 pies sobre el piso","48 pulgadas sobre el piso"],"re":"Los límites de alcance frontal de la ADA ubican la parte operable a no más de 48 pulgadas sobre el piso terminado para que sea alcanzable."},
  {"id":27,"q":"En un sistema electrónico de control de acceso, el dispositivo que lee una credencial y la envía al controlador es el:","opts":["Cerradero eléctrico","Lector de tarjetas","Contacto de puerta","Botón de solicitud de salida"],"re":"El lector de tarjetas lee la credencial (tarjeta, llavero, PIN, biometría) y pasa los datos al controlador, que decide si desbloquea."},
  {"id":28,"q":"Una cerradura magnética (maglock) en una puerta con control de acceso suele cablearse para ser:","opts":["De fallo seguro cerrado (permanece cerrada al cortarse la energía)","Solo mecánica","A prueba de fallos seguro (se desbloquea al cortarse la energía)","Siempre desbloqueada"],"re":"Un maglock sujeta por electroimán, así que cortar la energía lo libera (a prueba de fallos), importante para la salida cuando falla la energía."},
  {"id":29,"q":"Un dispositivo de solicitud de salida (REX) se usa para:","opts":["Indicar al controlador que libere la puerta para quien sale","Leer tarjetas de acceso","Activar la alarma de incendios","Alimentar la cámara"],"re":"El REX (sensor de movimiento o botón) avisa al controlador que alguien sale, así la cerradura se libera sin registrar una alarma de puerta forzada."},
  {"id":30,"q":"El cable coaxial y el conector usados tradicionalmente para video CCTV analógico son:","opts":["Cat 6 con RJ45","Coaxial RG-59 con conectores BNC","Dos pares con terminales de tornillo","Fibra monomodo con ST"],"re":"El CCTV analógico usa tradicionalmente coaxial RG-59 (o RG-6) de 75 ohmios terminado con conectores BNC (de bayoneta)."},
  {"id":31,"q":"El cable coaxial usado para video tiene una impedancia característica de:","opts":["50 ohmios","100 ohmios","75 ohmios","300 ohmios"],"re":"El coaxial de video como RG-59 y RG-6 es de 75 ohmios; igualar la impedancia evita reflexiones que distorsionan la imagen."},
  {"id":32,"q":"Un interruptor de posición de puerta (contacto de puerta) en un sistema de seguridad informa:","opts":["La temperatura en la puerta","El número de tarjeta usado","El enfoque de la cámara","Si la puerta está abierta o cerrada"],"re":"El contacto de puerta es un interruptor magnético que indica al sistema si la puerta está abierta o cerrada, permitiendo alertas de puerta forzada o mantenida abierta."},
  {"id":33,"q":"Una cámara de vigilancia IP (de red) se diferencia de una analógica en que:","opts":["No puede grabar video","No requiere cableado","Solo funciona de noche","Envía video digital por la red de datos"],"re":"Una cámara IP digitaliza el video y lo envía por la LAN (a menudo alimentada por PoE en el mismo cable), a diferencia de una analógica por coaxial."},
  {"id":34,"q":"Un sensor de movimiento infrarrojo pasivo (PIR) detecta el movimiento al percibir:","opts":["Ondas de sonido","Cambios en la energía infrarroja (calor) en su campo de visión","Señales de radio de los teléfonos","La luz de las ventanas"],"re":"Un sensor PIR reacciona a los cambios de calor infrarrojo cuando un cuerpo cálido cruza sus zonas de detección."},
  {"id":35,"q":"En una red de área local con cableado estructurado, los dispositivos suelen conectarse a través de un:","opts":["Switch de red","Varilla de tierra","Panel de alarma contra incendios","Divisor de coaxial"],"re":"Un switch de red es el punto central de conexión que reenvía los datos entre los dispositivos conectados en una LAN."},
  {"id":36,"q":"La alimentación por Ethernet (PoE) es útil porque:","opts":["Aumenta la longitud del cable a una milla","Elimina la necesidad de un switch","Entrega potencia de CC y datos a un dispositivo por el mismo cable","Convierte video en audio"],"re":"PoE lleva potencia de CC de bajo voltaje y datos en un solo cable de par trenzado, alimentando dispositivos como teléfonos IP, cámaras y puntos de acceso."},
  {"id":37,"q":"El PoE estándar (IEEE 802.3af) suministra energía a un voltaje nominal de unos:","opts":["12 voltios","120 voltios","240 voltios","48 voltios"],"re":"El PoE opera alrededor de 48 voltios de CC nominales; el 802.3af entrega hasta unos 15.4 W en la fuente (cerca de 12.95 W en el dispositivo)."},
  {"id":38,"q":"La dirección de hardware única de un dispositivo en una red local es su:","opts":["Dirección MAC","Número de estación manual","Código BNC","Clasificación de candelas"],"re":"La dirección MAC es el identificador de hardware único grabado en la interfaz de red; las direcciones IP se asignan lógicamente por encima de ella."},
  {"id":39,"q":"En un sistema de cableado estructurado, el lugar central donde se termina e interconecta el cableado horizontal es el:","opts":["Cuarto de telecomunicaciones (clóset de cableado)","Penetración del techo","Panel eléctrico principal","Estructura de estacionamiento"],"re":"El cableado horizontal va desde cada área de trabajo hasta un cuarto de telecomunicaciones (clóset de cableado), donde termina en paneles de parcheo."},
  {"id":40,"q":"Un panel de parcheo en un clóset de cableado se usa para:","opts":["Generar energía eléctrica","Terminar y organizar los tendidos horizontales para la interconexión","Detectar humo","Solo amplificar audio"],"re":"Los cables horizontales se ponchan en el panel de parcheo, luego cables cortos interconectan cada puerto con un switch, manteniendo el sistema ordenado."},
  {"id":41,"q":"En un sistema de megafonía o anuncios públicos, un sistema de distribución de 70 voltios se usa para:","opts":["Alimentar la alarma de incendios","Reemplazar el switch de red","Cargar baterías","Alimentar de forma eficiente muchas bocinas en tendidos largos"],"re":"Un sistema de 70 voltios (de voltaje constante) permite que muchas bocinas tomen poca potencia en tendidos largos con un calibre manejable y baja pérdida."},
  {"id":42,"q":"La atenuación en un cable de comunicaciones se refiere a:","opts":["El color del cable","El número de conductores","La pérdida de intensidad de la señal con la distancia","La clasificación de voltaje"],"re":"La atenuación es la pérdida de señal al viajar por el cable; aumenta con la longitud y la frecuencia, por eso los tendidos tienen límites de distancia."},
  {"id":43,"q":"El Artículo 725 del NEC cubre los circuitos Clase 1, Clase 2 y Clase 3 de:","opts":["Conductores de acometida","Solo circuitos de alarma contra incendios","Solo fibra óptica","Control remoto, señalización y energía limitada"],"re":"El Artículo 725 rige los circuitos Clase 1, 2 y 3 de control remoto, señalización y energía limitada, la base de la mayoría de los controles de bajo voltaje."},
  {"id":44,"q":"Un circuito Clase 2 de energía limitada se considera seguro principalmente porque:","opts":["Usa conductores muy gruesos","Limita el voltaje y la potencia a niveles bajos","Siempre va en tubería","No conduce corriente"],"re":"Los circuitos Clase 2 limitan el voltaje y la potencia disponible (una fuente listada limita la energía), por lo que se consideran seguros ante incendio y descarga y permiten métodos de cableado más flexibles."},
  {"id":45,"q":"El Artículo 760 del NEC cubre específicamente la instalación de:","opts":["Cableado de piscinas","Paneles solares","Controladores de motor","Circuitos de sistemas de alarma contra incendios"],"re":"El Artículo 760 cubre los circuitos de sistemas de alarma contra incendios, incluidos los tipos de energía limitada (PLFA) y no limitada (NPLFA) y sus requisitos de cable."},
  {"id":46,"q":"El Artículo 770 del NEC se aplica a:","opts":["Electrodos de puesta a tierra","Tableros de distribución","Cables y canalizaciones de fibra óptica","Dispositivos de sobrecorriente de circuito ramal"],"re":"El Artículo 770 cubre los cables y canalizaciones de fibra óptica, incluida la clasificación e instalación de la fibra en edificios."},
  {"id":47,"q":"El Artículo 800 del NEC rige los circuitos de comunicaciones, incluido el requisito de instalar un protector primario:","opts":["En el dispositivo más lejano","Solo en el ático","Lo más cerca posible de donde el cable entra al edificio","Dentro de cada jack"],"re":"Para circuitos expuestos a rayos o contacto con energía, el Artículo 800 exige un protector primario listado colocado lo más cerca posible del punto de entrada."},
  {"id":48,"q":"El cable de comunicaciones con clasificación plenum (tipo CMP) se requiere donde el cable pasa:","opts":["Bajo tierra","Por espacios de manejo de aire (plenum)","Solo dentro de tubería metálica","A la intemperie"],"re":"El cable plenum CMP tiene baja propagación de llama y humo, por eso se exige en espacios plenum usados para mover aire de HVAC; puede sustituir al cable riser pero no al revés."},
  {"id":49,"q":"El conductor de unión/puesta a tierra para un protector primario de comunicaciones debe ser:","opts":["Lo más largo posible","Solo aluminio desnudo","Clasificado al menos a 600 voltios","Lo más corto y recto posible"],"re":"Mantener el conductor de unión corto y recto da a las corrientes de sobretensión un camino de baja impedancia a tierra, mejorando la protección."},
  {"id":50,"q":"Una terminación de unión entre sistemas (IBT) proporciona:","opts":["Un lugar para empalmar conductores de potencia","Un punto accesible para unir comunicaciones, CATV y otros sistemas al sistema de electrodos de tierra","Luces estroboscópicas extra de alarma","Una batería de respaldo"],"re":"La IBT es un punto de conexión accesible para que comunicaciones, CATV, satélite y sistemas similares se unan al sistema de electrodos de tierra del edificio, manteniéndolos al mismo potencial."}
];
